import type { LabelHTMLAttributes } from "react";
import { forwardRef, useId } from "react";
import { clsx } from "clsx";
import { useRadioGroupContext } from "../RadioGroup";
import { Label, type LabelCustomProps } from "../Label";
import { Hint, type HintCustomProps } from "../Hint";
import { RadioItem, type RadioItemProps } from "../RadioItem";
import * as styles from "./RadioButton.css";

export type RadioButtonLabel = Omit<LabelCustomProps, "required">;

export type RadioButtonHint = HintCustomProps;

export interface RadioButtonCustomProps {
  /**
   * The visible label configuration
   */
  label: RadioButtonLabel;

  /**
   * Optional supporting text displayed under the label
   */
  hint?: RadioButtonHint | undefined;

  /**
   * Optional class applied to the root element
   */
  className?: string;
}

type RadioItemPropKeysToOmit = "className" | "children";

type RadioItemPropsSubset = Omit<RadioItemProps, RadioItemPropKeysToOmit>;

// Props that go to the label element (excluding RadioItem props and custom props)
type LabelPropsToOmit =
  | keyof RadioButtonCustomProps
  | keyof RadioItemPropsSubset;

export interface RadioButtonProps
  extends
    RadioItemPropsSubset,
    RadioButtonCustomProps,
    Omit<LabelHTMLAttributes<HTMLLabelElement>, LabelPropsToOmit> {}

const mergeIds = (...ids: Array<string | undefined>): string | undefined => {
  const filtered = ids.filter(Boolean) as string[];
  return filtered.length > 0 ? filtered.join(" ") : undefined;
};

export const RadioButton = forwardRef<HTMLLabelElement, RadioButtonProps>(
  (
    {
      // Custom props
      label,
      hint,
      className,
      // RadioItem props
      id,
      value,
      size,
      name,
      hideFocusRing,
      "aria-label": ariaLabel,
      "aria-describedby": ariaDescribedBy,
      "aria-labelledby": ariaLabelledBy,
      disabled = false,
      // Rest are label element props (forwarded from Slot)
      ...labelProps
    },
    ref
  ) => {
    const generatedId = useId();
    const radioId = id ?? generatedId;
    const labelId = `${radioId}-label`;
    const hintId = hint ? `${radioId}-hint` : undefined;

    const describedBy = mergeIds(ariaDescribedBy, hintId);
    const labelledBy = mergeIds(ariaLabelledBy, labelId);

    // Get group-level disabled state from context
    const state = useRadioGroupContext();
    // Combine item-level disabled with group-level disabled
    const isDisabled = disabled || state.isDisabled;

    return (
      <label
        ref={ref}
        {...labelProps}
        className={clsx(
          styles.container,
          isDisabled && styles.containerDisabled,
          className
        )}
      >
        <RadioItem
          id={radioId}
          value={value}
          disabled={disabled}
          {...(size !== undefined && { size })}
          {...(name !== undefined && { name })}
          {...(hideFocusRing !== undefined && { hideFocusRing })}
          {...(ariaLabel !== undefined && { "aria-label": ariaLabel })}
          {...(labelledBy !== undefined && { "aria-labelledby": labelledBy })}
          {...(describedBy !== undefined && {
            "aria-describedby": describedBy,
          })}
        />
        <span className={styles.textContainer}>
          <Label variant="normal" {...label} id={labelId} asChild>
            <span>{label.children}</span>
          </Label>
          {hint && <Hint {...hint} id={hintId} />}
        </span>
      </label>
    );
  }
);

RadioButton.displayName = "RadioButton";
